import azure.functions as func
import json
import logging
from datetime import datetime

app = func.FunctionApp()

@app.function_name(name="PaymentWebhook")
@app.route(route="webhook/payment", methods=["POST"], auth_level=func.AuthLevel.ANONYMOUS)
def payment_webhook(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Payment webhook triggered')
    
    try:
        req_body = req.get_json()
        
        if not req_body:
            return func.HttpResponse(
                json.dumps({"error": "Request body is required"}),
                status_code=400,
                mimetype="application/json"
            )
        
        payment_id = req_body.get('payment_id')
        status = req_body.get('status')
        amount = req_body.get('amount')
        currency = req_body.get('currency')
        provider = req_body.get('provider')
        transaction_id = req_body.get('transaction_id')
        customer_id = req_body.get('customer_id')
        
        if not all([payment_id, status, amount, currency, provider]):
            return func.HttpResponse(
                json.dumps({"error": "Missing required fields: payment_id, status, amount, currency, provider"}),
                status_code=400,
                mimetype="application/json"
            )
        
        payment_data = {
            "payment_id": payment_id,
            "status": status,
            "amount": amount,
            "currency": currency,
            "provider": provider,
            "transaction_id": transaction_id,
            "customer_id": customer_id,
            "timestamp": datetime.utcnow().isoformat(),
            "processed": True
        }
        
        logging.info(f"Processing payment notification: {json.dumps(payment_data)}")
        
        if status == "completed":
            logging.info(f"Payment {payment_id} completed successfully")
        elif status == "failed":
            logging.warning(f"Payment {payment_id} failed")
        elif status == "pending":
            logging.info(f"Payment {payment_id} is pending")
        elif status == "refunded":
            logging.info(f"Payment {payment_id} was refunded")
        else:
            logging.warning(f"Unknown payment status: {status}")
        
        response_data = {
            "success": True,
            "message": "Payment notification processed successfully",
            "payment_id": payment_id,
            "received_at": payment_data["timestamp"]
        }
        
        return func.HttpResponse(
            json.dumps(response_data),
            status_code=200,
            mimetype="application/json"
        )
        
    except ValueError as e:
        logging.error(f"Invalid JSON in request body: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": "Invalid JSON format"}),
            status_code=400,
            mimetype="application/json"
        )
    
    except Exception as e:
        logging.error(f"Error processing payment webhook: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": "Internal server error", "details": str(e)}),
            status_code=500,
            mimetype="application/json"
        )